import pymysql
import os
import json
from flask import Request

def search_database(request: Request):
    db_user = os.environ.get('DB_USER', 'root')
    db_password = os.environ.get('DB_PASSWORD', '')
    db_name = os.environ.get('DB_NAME', 'mydb')
    db_host = os.environ.get('DB_HOST', 'localhost')
    
    connection = None
    try:
        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            cursorclass=pymysql.cursors.DictCursor
        )
        
        request_json = request.get_json(silent=True)
        request_args = request.args
        
        table = None
        filters = {}
        order_by = None
        limit = 100
        
        if request_json:
            table = request_json.get('table', 'users')
            filters = request_json.get('filters', {})
            order_by = request_json.get('order_by')
            limit = request_json.get('limit', 100)
        elif request_args:
            table = request_args.get('table', 'users')
            order_by = request_args.get('order_by')
            limit = int(request_args.get('limit', 100))
            for key, value in request_args.items():
                if key not in ['table', 'order_by', 'limit']:
                    filters[key] = value
        else:
            table = 'users'
        
        query = f"SELECT * FROM {table}"
        
        if filters:
            where_clauses = []
            for column, value in filters.items():
                if isinstance(value, str):
                    where_clauses.append(f"{column} = '{value}'")
                else:
                    where_clauses.append(f"{column} = {value}")
            
            query += " WHERE " + " AND ".join(where_clauses)
        
        if order_by:
            query += f" ORDER BY {order_by}"
        
        query += f" LIMIT {limit}"
        
        with connection.cursor() as cursor:
            cursor.execute(query)
            results = cursor.fetchall()
        
        return json.dumps({
            'success': True,
            'count': len(results),
            'data': results
        }), 200, {'Content-Type': 'application/json'}
        
    except Exception as e:
        return json.dumps({
            'success': False,
            'error': str(e)
        }), 500, {'Content-Type': 'application/json'}
        
    finally:
        if connection:
            connection.close()


